    static double temperature = 100.0;
    static const double cooling_rate = 0.99;

    // Population of solutions
    const int POPULATION_SIZE = 5;
    struct Solution {
        double arrival;
        double area_flow;
        float area;
        uint32_t size;
        uint8_t cut;
        uint8_t phase;
    };
    Solution best_solutions[POPULATION_SIZE];

