            if (arrival_delta < 0 && area_delta > 0) arrival_weight *= 1.05;
            if (area_delta < 0 && arrival_delta > 0) area_weight *= 1.05;

            double obj_delta = arrival_weight * arrival_delta + area_weight * area_delta;
            double diversity_term = 1.0 - (cut->data.selection_count / (1.0 + cut->data.total_evaluations));

            // Temperature-dependent probability with adaptive scaling
            double probability = exp(-obj_delta / (temperature * (1.0 + diversity_term * (temperature / 10.0))));
